import math

class Solution:
    def find132pattern(self, nums: list[int]) -> bool:
        n = len(nums)
        if n < 3:
            return False

        s3_val = -math.inf
        stack = []

        for i in range(n - 1, -1, -1):
            num = nums[i]

            if num < s3_val:
                return True

            while stack and num > stack[-1]:
                s3_val = stack.pop()

            stack.append(num)

        return False
